const supaGetTeamCheckins = async (startDate, endDate) => {
  if (!supabase) return [];
  try {
    let q = supabase.from("checkins").select("*").order("check_in_at", { ascending: false });
    if (startDate) q = q.gte("check_in_at", startDate);
    if (endDate) q = q.lte("check_in_at", endDate);
    const { data, error } = await q.limit(200);
    if (error) { console.error("supaGetTeamCheckins error:", error); return []; }
    return data || [];
  } catch(e) { console.error("supaGetTeamCheckins exception:", e); return []; }
};

const LOGO_B64 = "data:image/png;base64,";
const THEME_MAP = { "default": "#BBF246", "blue": "#3B82F6", "purple": "#8B5CF6", "pink": "#EC4899", "orange": "#F59E0B", "red": "#EF4444", "cyan": "#06B6D4", "emerald": "#10B981", "indigo": "#6366F1", "rose": "#F43F5E", "amber": "#D97706", "teal": "#14B8A6", "sky": "#0EA5E9", "fuchsia": "#D946EF", "slate": "#64748B" };
function getB(isDark, accent, prefs) {
  const a = accent || "#BBF246";
  const p = prefs || {};
  const hexToLum = (h) => { const r = parseInt(h.slice(1,3),16)/255, g = parseInt(h.slice(3,5),16)/255, b = parseInt(h.slice(5,7),16)/255; return 0.299*r + 0.587*g + 0.114*b; };
  const onAccent = hexToLum(a) > 0.45 ? "#192126" : "#ffffff";
  const base = isDark ? {
    dark: "#192126", accent: a, muted: "#8B9099", text: "#E8EAED", bg: "#0F1419", bgCard: "#1C2228", bgInput: "#1C2228",
    border: "rgba(255,255,255,0.08)", blue: "#60A5FA", green: "#34D399", red: "#F87171", orange: "#FBBF24", purple: "#A78BFA", yellow: "#FBBF24",
    pink: "#F472B6", cyan: "#22D3EE", textOnAccent: onAccent,
  } : {
    dark: "#192126", accent: a, muted: "#8B8F92", text: "#192126", bg: "#F7F7F8", bgCard: "#fff", bgInput: "#fff",
    border: "rgba(11,35,66,0.08)", blue: "#3B82F6", green: "#10B981", red: "#EF4444", orange: "#F59E0B", purple: "#8B5CF6", yellow: "#F59E0B",
    pink: "#EC4899", cyan: "#06B6D4", textOnAccent: onAccent,
  };
  /* Apply theme color overrides from uiPrefs */
  if(p.customBg) base.bg = p.customBg;
  if(p.customBgCard) base.bgCard = p.customBgCard;
  if(p.customBgInput) base.bgInput = p.customBgInput;
  if(p.customText) base.text = p.customText;
  if(p.customMuted) base.muted = p.customMuted;
  if(p.customBorder) base.border = p.customBorder;
  /* Derived */
  base.iconColor = p.iconColor || base.accent;
  base.navActive = p.navActiveColor || base.textOnAccent;
  base.navInactive = p.navInactiveColor || "rgba(255,255,255,0.45)";
  base.blockBg = p.blockBg || (isDark ? "rgba(255,255,255,0.04)" : "rgba(0,0,0,0.03)");
  base.iconFill = p.iconFill || "outlined";
  base.liquidGlass = !!p.liquidGlass;
  base.hasBgImage = !!p.bgImage && p.bgImage !== "none";
  base.transparent = base.liquidGlass || base.hasBgImage;
  /* Compute the actual body background */
  const bgPresets = {
    gradient: "linear-gradient(135deg, #667eea 0%, #764ba2 100%)",
    mesh1: "linear-gradient(135deg, #0F2027 0%, #203A43 50%, #2C5364 100%)",
    mesh2: "linear-gradient(135deg, #a18cd1 0%, #fbc2eb 50%, #a6c1ee 100%)",
    mesh3: "linear-gradient(135deg, #0c3547 0%, #1a6b6d 40%, #48c6ef 100%)",
    mesh4: "linear-gradient(135deg, #fa709a 0%, #fee140 100%)",
    mesh5: "linear-gradient(135deg, #134e5e 0%, #71b280 100%)",
    mesh6: "linear-gradient(135deg, #0f0c29 0%, #302b63 50%, #24243e 100%)",
  };
  const bgKey = p.bgImage || "none";
  const bgUrl = p.bgImageUrl || "";
  if (bgKey === "custom" && bgUrl) base.bodyBg = `url(${bgUrl}) center/cover fixed no-repeat`;
  else if (bgKey !== "none" && bgPresets[bgKey]) base.bodyBg = bgPresets[bgKey];
  else if (base.liquidGlass) base.bodyBg = isDark ? "linear-gradient(135deg, #0C111B 0%, #1A1040 50%, #0C111B 100%)" : "linear-gradient(135deg, #E8ECF4 0%, #D5DEF0 30%, #E0D4F0 60%, #E8ECF4 100%)";
  else base.bodyBg = base.bg;  if (base.liquidGlass) {
    base.glassBg = isDark ? "rgba(15,20,25,0.65)" : "rgba(255,255,255,0.55)";
    base.glassCard = isDark ? "rgba(28,34,40,0.55)" : "rgba(255,255,255,0.45)";
    base.glassBorder = isDark ? "rgba(255,255,255,0.12)" : "rgba(255,255,255,0.6)";
    base.glassShadow = isDark ? "0 8px 32px rgba(0,0,0,0.3), inset 0 1px 0 rgba(255,255,255,0.06)" : "0 8px 32px rgba(0,0,0,0.08), inset 0 1px 0 rgba(255,255,255,0.8)";
    base.glassBlur = "blur(24px) saturate(180%)";
  }
  return base;
}
let B = getB(false, "#BBF246");

/* ═══════════════════════ SVG ICONS ═══════════════════════ */
/* ── Desktop detection hook ── */
const useIsDesktop = () => {
  const [isDesktop, setIsDesktop] = useState(() => typeof window !== "undefined" && window.innerWidth >= 900);
  useEffect(() => {
    const mq = window.matchMedia("(min-width: 900px)");
    const handler = (e) => setIsDesktop(e.matches);
    mq.addEventListener("change", handler);
    return () => mq.removeEventListener("change", handler);
  }, []);
  useEffect(() => {
    if (isDesktop) {
      document.documentElement.classList.add("uh-desktop");
    } else {
      document.documentElement.classList.remove("uh-desktop");
    }
  }, [isDesktop]);
  return isDesktop;
};

/* ── Desktop Sidebar ── */
const DesktopSidebar = ({ tabs, activeTab, onTabChange, user, logo, title, accentColor, onLogout, sections }) => {
  const accent = accentColor || B.accent;
  const SECTIONS = sections || [
    { label: null, keys: ["home"] },
    { label: "Gestão", keys: ["content","clients","chat","team","calendar"] },
    { label: "Análise", keys: ["reports","financial","gamify","match4biz"] },
    { label: "Ferramentas", keys: ["library","feedplanner","academy","news","ideas","ai"] },
    { label: "Sistema", keys: ["checkin","help","settings"] },
  ];
  return (
    <div className="d-sidebar" style={{ fontFamily:"'Figtree',sans-serif" }}>
      {/* Brand header */}
      <div style={{ padding:"22px 20px 18px", display:"flex", alignItems:"center", gap:12 }}>
        {logo ? <img src={logo} alt="" style={{ width:36, height:36, borderRadius:11, objectFit:"cover" }} /> : <div style={{ width:36, height:36, borderRadius:11, background:`linear-gradient(135deg, ${accent}, ${accent}BB)`, display:"flex", alignItems:"center", justifyContent:"center", fontSize:16, fontWeight:900, color:"#0D0D0D", boxShadow:`0 2px 10px ${accent}40` }}>{(title||"U")[0]}</div>}
        <div style={{ flex:1, minWidth:0 }}>
          <p style={{ fontSize:15, fontWeight:800, color:B.text, overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap", letterSpacing:"-0.3px" }}>{title || "UniqueHub"}</p>
        </div>
      </div>
      {/* Navigation sections */}
      <div style={{ flex:1, overflowY:"auto", padding:"0 12px", scrollbarWidth:"thin", scrollbarColor:`${B.border} transparent` }}>
        {SECTIONS.map((sec, si) => {
          const items = sec.keys.map(k => tabs.find(t => t.k === k)).filter(Boolean);
          if (items.length === 0) return null;
          return <div key={si} style={{ marginBottom:6 }}>
            {sec.label && <p style={{ fontSize:9, fontWeight:700, color:B.muted, textTransform:"uppercase", letterSpacing:1.5, padding:"14px 8px 6px", opacity:0.5 }}>{sec.label}</p>}
            {items.map(t => {
              const isActive = activeTab === t.k;
              return <button key={t.k} onClick={() => onTabChange(t.k)} style={{ display:"flex", alignItems:"center", gap:10, width:"100%", padding:"8px 10px", borderRadius:10, border:"none", cursor:"pointer", fontFamily:"inherit", fontSize:13, fontWeight:isActive?600:400, color:isActive?B.text:`${B.muted}`, background:isActive?`${accent}12`:"transparent", marginBottom:1, transition:"all .12s ease", textAlign:"left", letterSpacing:"-0.1px" }}>
                <span style={{ width:18, height:18, display:"flex", justifyContent:"center", alignItems:"center", flexShrink:0, opacity:isActive?1:0.5 }}>{typeof t.i === "function" ? t.i(isActive?accent:B.muted) : t.i}</span>
                <span style={{ flex:1 }}>{t.l}</span>
                {t.badge > 0 && <span style={{ background:accent, color:"#0D0D0D", fontSize:9, fontWeight:700, padding:"2px 6px", borderRadius:8, minWidth:16, textAlign:"center" }}>{t.badge}</span>}
              </button>;
            })}
          </div>;
        })}
      </div>
      {/* User footer */}
      <div style={{ padding:"14px 16px", borderTop:`1px solid ${B.border}`, display:"flex", alignItems:"center", gap:10 }}>
        <div style={{ width:34, height:34, borderRadius:10, background:`${accent}15`, display:"flex", alignItems:"center", justifyContent:"center", fontSize:13, fontWeight:800, color:accent, flexShrink:0 }}>{(user?.name||user?.email||"U")[0].toUpperCase()}</div>
        <div style={{ flex:1, minWidth:0 }}>
          <p style={{ fontSize:12, fontWeight:600, color:B.text, overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap" }}>{user?.name || user?.email}</p>
          <p style={{ fontSize:10, color:B.muted, overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap" }}>{user?.role || ""}</p>
        </div>
        {onLogout && <button onClick={onLogout} title="Sair" style={{ width:28, height:28, borderRadius:8, border:"none", cursor:"pointer", background:"transparent", display:"flex", alignItems:"center", justifyContent:"center", color:B.muted, flexShrink:0, opacity:0.5 }}>
          <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round"><path d="M9 21H5a2 2 0 01-2-2V5a2 2 0 012-2h4"/><polyline points="16 17 21 12 16 7"/><line x1="21" y1="12" x2="9" y2="12"/></svg>
        </button>}
      </div>
    </div>
  );
};

/* ── Stable carousel components (extracted to prevent re-mount on parent re-render) ── */
const _ReelsCarousel = React.memo(({ allSlides, coverCount, B }) => {
  const [slide, setSlide] = React.useState(0);
  const ref = React.useRef(null);
  const scrollTo = (idx) => { if(ref.current) ref.current.scrollTo({ left: idx * ref.current.offsetWidth, behavior:"smooth" }); };
  const onScroll = () => { if(!ref.current) return; const w=ref.current.offsetWidth; setSlide(Math.round(ref.current.scrollLeft/w)); };
  const isCover = slide < coverCount;
  return <div style={{ marginTop:8, borderRadius:20, overflow:"hidden", background:B.bgCard, border:`1px solid ${B.border}` }}>
    <div style={{ display:"flex", borderBottom:`1px solid ${B.border||"rgba(0,0,0,0.06)"}` }}>
      <button onClick={()=>scrollTo(0)} style={{ flex:1, padding:"12px 0", background:isCover?`${B.accent}10`:"transparent", border:"none", borderBottom:isCover?`3px solid ${B.accent}`:"3px solid transparent", cursor:"pointer", fontFamily:"inherit", fontSize:13, fontWeight:700, color:isCover?B.accent:B.muted, display:"flex", alignItems:"center", justifyContent:"center", gap:6 }}>
        <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round"><rect x="3" y="3" width="18" height="18" rx="2"/><circle cx="8.5" cy="8.5" r="1.5"/><polyline points="21 15 16 10 5 21"/></svg> Capa
      </button>
      <button onClick={()=>scrollTo(coverCount)} style={{ flex:1, padding:"12px 0", background:!isCover?`${B.blue||"#3B82F6"}10`:"transparent", border:"none", borderBottom:!isCover?`3px solid ${B.blue||"#3B82F6"}`:"3px solid transparent", cursor:"pointer", fontFamily:"inherit", fontSize:13, fontWeight:700, color:!isCover?(B.blue||"#3B82F6"):B.muted, display:"flex", alignItems:"center", justifyContent:"center", gap:6 }}>
        <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round"><polygon points="23 7 16 12 23 17 23 7"/><rect x="1" y="5" width="15" height="14" rx="2"/></svg> Vídeo {isCover && <span style={{ fontSize:9, fontWeight:600, opacity:0.7 }}>→</span>}
      </button>
    </div>
    <div ref={ref} onScroll={onScroll} style={{ display:"flex", overflowX:"auto", scrollSnapType:"x mandatory", scrollbarWidth:"none", WebkitOverflowScrolling:"touch" }}>
      {allSlides.map((f,i) => {
        const isVid = /\.(mp4|mov|webm|avi)$/i.test(f.name||f.url||"") || f.type?.startsWith("video/");
        return <div key={i} style={{ width:"100%", flexShrink:0, scrollSnapAlign:"start", background:"#000", minHeight:300 }}>
          {isVid ? <video src={f.url} controls playsInline style={{ width:"100%", maxHeight:"70vh", objectFit:"contain" }} />
                 : <img src={f.url} alt="" style={{ width:"100%", maxHeight:"70vh", objectFit:"contain" }} />}
        </div>;
      })}
    </div>
  </div>;
});
const _CarouselView = React.memo(({ imgFiles, B }) => {
  const [slide, setSlide] = React.useState(0);
  const ref = React.useRef(null);
  const onScroll = () => { if(!ref.current) return; const w=ref.current.offsetWidth; setSlide(Math.round(ref.current.scrollLeft/w)); };
  return <div style={{ marginTop:8, borderRadius:20, overflow:"hidden", background:B.bgCard, border:`1px solid ${B.border}`, padding:0 }}>
    <div ref={ref} onScroll={onScroll} style={{ display:"flex", overflowX:"auto", scrollSnapType:"x mandatory", scrollbarWidth:"none", WebkitOverflowScrolling:"touch" }}>
      {imgFiles.map((f,i) => <img key={i} src={f.url} alt="" style={{ width:"100%", flexShrink:0, scrollSnapAlign:"start", objectFit:"contain", background:"#000", maxHeight:"70vh" }} />)}
    </div>
    {imgFiles.length > 1 && <div style={{ display:"flex", justifyContent:"center", gap:6, padding:"10px 0" }}>
      {imgFiles.map((_,i) => <div key={i} style={{ width:slide===i?20:8, height:8, borderRadius:4, background:slide===i?B.accent:`${B.muted}30`, transition:"all .3s" }} />)}
    </div>}
    {imgFiles.length > 1 && <p style={{ textAlign:"center", fontSize:11, color:B.muted, paddingBottom:10 }}>{slide+1} de {imgFiles.length} · Arraste para ver mais</p>}
  </div>;
});

