/* ── CollapseHeader: reusable collapsible page header ── */
const CollapseHeader = ({ icon, label, title, stats=[], onAdd, onBack, collapsed }) => { const _dsk = typeof document !== "undefined" && document.documentElement.classList.contains("uh-desktop"); return (
  <div style={{
    position:"sticky", top:0, zIndex:20, background:B.bgCard,
    borderBottom: collapsed ? `1px solid ${B.border}` : "none",
    borderRadius: collapsed ? 0 : "0 0 26px 26px",
    boxShadow: collapsed ? "none" : "0 4px 20px rgba(0,0,0,0.08)",
    transition:"all .26s cubic-bezier(.4,0,.2,1)", overflow:"hidden",
  }}>
    {collapsed ? (
      <div style={{ display:"flex", alignItems:"center", gap:12, padding:"10px 20px" }}>
        {onBack && <button onClick={onBack} className="ib" style={{ border:`1.5px solid ${B.border}`, flexShrink:0 }}>{IC.back()}</button>}
        <div style={{ width:32, height:32, borderRadius:10, background:`${B.accent}15`, display:"flex", alignItems:"center", justifyContent:"center", flexShrink:0 }}>
          {typeof icon === "function" ? icon(B.accent) : icon}
        </div>
        <div style={{ flex:1, minWidth:0 }}>
          <p style={{ fontSize:13, fontWeight:800, color:B.text }}>{title}</p>
          {stats.length>0 && <p style={{ fontSize:10, color:B.muted, marginTop:1 }}>{stats.map(s=>`${s.val} ${s.label}`).join(" · ")}</p>}
        </div>
        {onAdd && <button onClick={onAdd} style={{ width:34, height:34, borderRadius:10, background:B.accent, border:"none", display:"flex", alignItems:"center", justifyContent:"center", cursor:"pointer", flexShrink:0 }}>
          <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="#0D0D0D" strokeWidth="2.5" strokeLinecap="round"><line x1="12" y1="5" x2="12" y2="19"/><line x1="5" y1="12" x2="19" y2="12"/></svg>
        </button>}
      </div>
    ) : (
      <div style={{ padding: _dsk ? (onBack ? "28px 28px 24px" : "70px 28px 24px") : `calc(env(safe-area-inset-top,0px) + 20px) 20px 22px` }}>
        {onBack && <button onClick={onBack} className="ib" style={{ border:`1.5px solid ${B.border}`, marginBottom:8 }}>{IC.back()}</button>}
        <div style={{ display:"flex", alignItems:"flex-start", justifyContent:"space-between", marginBottom:stats.length?16:0 }}>
          <div>
            <p style={{ fontSize: _dsk ? 12 : 11, fontWeight:700, color:B.accent, textTransform:"uppercase", letterSpacing:1.2, marginBottom:4 }}>{label}</p>
            <h2 style={{ fontSize: _dsk ? 28 : 24, fontWeight:900, color:B.text, letterSpacing:"-0.5px", lineHeight:1 }}>{title}</h2>
          </div>
          {onAdd && <button onClick={onAdd} style={{ width:44, height:44, borderRadius:"50%", background:B.accent, border:"none", display:"flex", alignItems:"center", justifyContent:"center", cursor:"pointer", flexShrink:0, boxShadow:`0 4px 14px ${B.accent}50` }}>
            <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="#0D0D0D" strokeWidth="2.5" strokeLinecap="round"><line x1="12" y1="5" x2="12" y2="19"/><line x1="5" y1="12" x2="19" y2="12"/></svg>
          </button>}
        </div>
        {stats.length>0 && (
          <div style={{ display:"flex", gap:10 }}>
            {stats.map((s,i) => (
              <div key={i} style={{ flex:1, background:i===0?`${B.accent}12`:B.bgCard, border:i===0?"none":`1px solid ${B.border}`, borderRadius:14, padding:"12px 14px" }}>
                <p style={{ fontSize:22, fontWeight:900, color:i===0?B.accent:B.text, lineHeight:1 }}>{s.val}</p>
                <p style={{ fontSize:10, color:B.muted, marginTop:3, fontWeight:600 }}>{s.label}</p>
              </div>
            ))}
          </div>
        )}
      </div>
    )}
  </div>
  ); };


function useToast() {
  const [toast, setToast] = useState(null);
  const showToast = (msg, duration) => { const isLong = msg && msg.includes("\n\n"); setToast(msg); setTimeout(() => setToast(null), duration || (isLong ? 6000 : 2800)); };
  const isError = toast && (toast.includes("Erro") || toast.includes("erro") || toast.includes("falh") || toast.includes("❌"));
  const isSuccess = toast && (toast.includes("✅") || toast.includes("✓") || toast.includes("Publicado") || toast.includes("criada") || toast.includes("Avançou"));
  const isGuide = toast && toast.includes("\n\n");
  const ToastEl = toast ? <div className="toast-anim" onClick={()=>setToast(null)} style={{ position:"fixed", top:"50%", left:"50%", transform:"translate(-50%, -50%)", background:"#1A1D23", backdropFilter:"blur(16px)", color:"#fff", padding: isGuide ? "14px 20px" : "12px 24px", borderRadius:14, fontSize: isGuide ? 12 : 13, fontWeight:600, zIndex:99999, boxShadow:"0 8px 40px rgba(0,0,0,0.4)", display:"flex", alignItems: isGuide ? "flex-start" : "center", gap:10, maxWidth:420, textAlign: isGuide ? "left" : "left", letterSpacing:-0.2, borderLeft: isError ? "3px solid #EF4444" : isSuccess ? "3px solid #BBF246" : "3px solid #3B82F6", whiteSpace: isGuide ? "pre-line" : "normal", lineHeight:1.5, cursor:"pointer" }}><div style={{ width:24, height:24, borderRadius:8, background: isError ? "#EF444420" : isSuccess ? "#BBF24620" : "#3B82F620", display:"flex", alignItems:"center", justifyContent:"center", flexShrink:0 }}>{isError ? <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="#EF4444" strokeWidth="2.5" strokeLinecap="round"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg> : isSuccess ? <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="#BBF246" strokeWidth="2.5" strokeLinecap="round"><polyline points="20 6 9 17 4 12"/></svg> : <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="#3B82F6" strokeWidth="2.5" strokeLinecap="round"><circle cx="12" cy="12" r="10"/><line x1="12" y1="8" x2="12" y2="12"/><line x1="12" y1="16" x2="12.01" y2="16"/></svg>}</div><span style={{ color:"#E2E8F0" }}>{toast.replace(/^[✅✓❌⚠️ℹ️📐]+\s*/, "")}</span></div> : null;
  return { toast, showToast, ToastEl };
}

